<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Track Booking Status</title>
<style>body{font-family:Inter,system-ui,sans-serif;background:#f8fafc;padding:40px;color:#0f172a}.wrap{max-width:820px;margin:0 auto}.stack{display:grid;gap:20px}.card{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:24px;box-shadow:0 12px 32px rgba(15,23,42,.06)}input{width:100%;padding:14px;border:1px solid #cbd5e1;border-radius:12px}button,.btn{margin-top:12px;background:#2563eb;border:0;color:#fff;padding:12px 18px;border-radius:12px;font-weight:600;text-decoration:none;display:inline-flex}.muted{color:#64748b}.row{display:grid;grid-template-columns:160px 1fr;gap:10px;padding:10px 0;border-bottom:1px solid #f1f5f9}.row:last-child{border-bottom:0}</style></head>
<body><div class="wrap"><div class="stack"><div class="card"><h1 style="margin-top:0">Track your booking</h1><p class="muted">Enter your booking reference or readable ID to check the latest status.</p><form method="GET"><input name="reference" placeholder="e.g. 100123 or booking UUID" value="{{ $reference }}"><button type="submit">Check status</button></form></div>@if($reference !== '')<div class="card">@if($booking)<h2 style="margin-top:0">Current status: {{ ucfirst(str_replace('_',' ', $booking->booking_status)) }}</h2><div class="row"><strong>Reference</strong><div>#{{ $booking->readable_id ?? $booking->id }}</div></div><div class="row"><strong>Scheduled</strong><div>{{ $booking->service_schedule ? \Carbon\Carbon::parse($booking->service_schedule)->format('d M Y H:i') : 'TBC' }}</div></div><div class="row"><strong>Provider</strong><div>{{ optional($booking->provider)->company_name ?: 'Assigned by dispatch' }}</div></div><div class="row"><strong>Payment</strong><div>{{ $booking->is_paid ? 'Paid' : 'Payment pending' }}</div></div><div class="row"><strong>Verification</strong><div>{{ $booking->is_verified ? 'Verified' : 'Awaiting verification' }}</div></div>@else<p>No booking found for that reference.</p>@endif</div>@endif<div class="card"><h2 style="margin-top:0">Need a new request?</h2><p class="muted">Return to your booking page or contact dispatch to reschedule.</p><a class="btn" href="javascript:history.back()">Go back</a></div></div></div></body></html>
